// ─────────────────────────────────────────────────────────────
//  Sidebar — navigation + system status
// ─────────────────────────────────────────────────────────────

const ShieldIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5">
    <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" />
  </svg>
);

const NAV_ICONS = {
  dashboard: (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <rect x="3" y="3" width="7" height="7" />
      <rect x="14" y="3" width="7" height="7" />
      <rect x="14" y="14" width="7" height="7" />
      <rect x="3" y="14" width="7" height="7" />
    </svg>
  ),
  alerts: (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z" />
      <line x1="12" y1="9" x2="12" y2="13" />
      <line x1="12" y1="17" x2="12.01" y2="17" />
    </svg>
  ),
  logs: (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" />
      <polyline points="14 2 14 8 20 8" />
      <line x1="16" y1="13" x2="8" y2="13" />
      <line x1="16" y1="17" x2="8" y2="17" />
    </svg>
  ),
  investigation: (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <circle cx="11" cy="11" r="8" />
      <line x1="21" y1="21" x2="16.65" y2="16.65" />
    </svg>
  ),
};

const NAV_ITEMS = [
  { key: "dashboard", label: "Dashboard" },
  { key: "alerts", label: "Alerts" },
  { key: "logs", label: "Logs" },
  { key: "investigation", label: "Investigation" },
];

function NavItem({ icon, label, active, onClick }) {
  return (
    <button
      onClick={onClick}
      style={{
        width: "100%",
        display: "flex",
        alignItems: "center",
        gap: 10,
        padding: "10px 20px",
        background: active ? "rgba(0,212,255,0.08)" : "transparent",
        border: "none",
        borderLeft: active ? "2px solid var(--accent)" : "2px solid transparent",
        color: active ? "var(--accent)" : "var(--muted)",
        cursor: "pointer",
        fontSize: 13,
        fontFamily: "var(--font-mono)",
        fontWeight: active ? 600 : 400,
        transition: "all 0.2s",
        textAlign: "left",
      }}
    >
      {icon}
      {label}
    </button>
  );
}

export default function Sidebar({ page, setPage }) {
  return (
    <div
      style={{
        width: 220,
        background: "var(--surface)",
        borderRight: "1px solid var(--border)",
        display: "flex",
        flexDirection: "column",
        flexShrink: 0,
        height: "100%",
      }}
    >
      {/* Logo */}
      <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "20px 20px 16px" }}>
        <div
          style={{
            width: 32,
            height: 32,
            background: "linear-gradient(135deg,#00d4ff,#0077ff)",
            borderRadius: 8,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            boxShadow: "0 0 16px rgba(0,212,255,0.4)",
            flexShrink: 0,
          }}
        >
          <ShieldIcon />
        </div>
        <div>
          <div
            style={{
              fontFamily: "var(--font-display)",
              fontWeight: 800,
              fontSize: 14,
              letterSpacing: "0.05em",
              color: "var(--text)",
            }}
          >
            SIEM
          </div>
          <div style={{ fontSize: 10, color: "var(--accent)", letterSpacing: "0.12em", fontWeight: 600 }}>
            DASHBOARD
          </div>
        </div>
      </div>

      <div style={{ borderTop: "1px solid var(--border)", marginBottom: 8 }} />

      {/* Section label */}
      <div
        style={{
          fontSize: 10,
          color: "var(--muted)",
          padding: "8px 20px 4px",
          letterSpacing: "0.12em",
          fontWeight: 600,
        }}
      >
        NAVIGATION
      </div>

      {/* Nav items */}
      {NAV_ITEMS.map(({ key, label }) => (
        <NavItem
          key={key}
          icon={NAV_ICONS[key]}
          label={label}
          active={page === key}
          onClick={() => setPage(key)}
        />
      ))}

      {/* System Status */}
      <div
        style={{
          marginTop: "auto",
          padding: "16px 20px",
          borderTop: "1px solid var(--border)",
        }}
      >
        <div
          style={{
            fontSize: 10,
            color: "var(--muted)",
            marginBottom: 8,
            letterSpacing: "0.1em",
            fontWeight: 600,
          }}
        >
          SYSTEM STATUS
        </div>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 6,
            fontSize: 11,
            color: "var(--green)",
          }}
        >
          <div
            style={{
              width: 6,
              height: 6,
              background: "var(--green)",
              borderRadius: "50%",
              animation: "pulse 2s infinite",
            }}
          />
          Wazuh Manager: Online
        </div>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 6,
            fontSize: 11,
            color: "var(--green)",
            marginTop: 6,
          }}
        >
          <div
            style={{
              width: 6,
              height: 6,
              background: "var(--green)",
              borderRadius: "50%",
              animation: "pulse 2s infinite",
              animationDelay: "0.5s",
            }}
          />
          Agents: 12 Active
        </div>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 6,
            fontSize: 11,
            color: "#ff8c00",
            marginTop: 6,
          }}
        >
          <div
            style={{
              width: 6,
              height: 6,
              background: "#ff8c00",
              borderRadius: "50%",
              animation: "pulse 2s infinite",
              animationDelay: "1s",
            }}
          />
          ELK Stack: Degraded
        </div>
      </div>
    </div>
  );
}
